import React, { useEffect, useRef, useState, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Polyline, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import toast from 'react-hot-toast';
import useStore from '../store/useStore';
import { geocodeSearch, calculateRoute } from '../services/api';
import { routeAPI, weatherAPI, aiAPI } from '../services/api';
import NavigationPanel from '../components/NavigationPanel';   // atau sesuai path Anda


// Panel impor – gunakan barrel
import {
  SearchPanel,
  RoutePanel,
  AIChatPanel,
  DriverPanel,
  ProfilePanel,
  WeatherPanel,
  HistoryPanel,
  SOSPanel,
  LayersPanel,
} from '../components/panels';

// Components impor – MapControls sebagai default, lainnya named
import MapControls, { AlertOverlay, RouteBar } from '../components';
import NavBar from '../components/NavBar';

// Fix Leaflet default icon
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

const createIcon = (color, size = 12) => L.divIcon({
  html: `<div style="width:${size}px;height:${size}px;border-radius:50%;background:${color};border:2.5px solid #fff;box-shadow:0 0 0 2px ${color}40"></div>`,
  className: '', iconSize: [size, size], iconAnchor: [size / 2, size / 2]
});

const createPinIcon = (color) => L.divIcon({
  html: `<div style="width:14px;height:14px;border-radius:50%;background:${color};border:2.5px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.4)"></div>`,
  className: '', iconSize: [14, 14], iconAnchor: [7, 7]
});

// Component untuk update peta view
function MapUpdater({ center, zoom }) {
  const map = useMap();
  useEffect(() => { if (center) map.setView(center, zoom || map.getZoom(), { animate: true }); }, [center, map, zoom]);
  return null;
}

export default function MainScreen() {
  const {
    user, userLocation, setUserLocation,
    origin, setOrigin, destination, setDestination,
    activeRoute, setActiveRoute, clearRoute,
    activePanel, setActivePanel,
    activeTab, setActiveTab,
    weather, setWeather,
    logout
  } = useStore();
  const [isNavigating, setIsNavigating] = useState(false);
  const [navigationRoute, setNavigationRoute] = useState(null);
  const [mapCenter, setMapCenter] = useState([-2.9761, 104.7754]);
  const [mapZoom, setMapZoom] = useState(13);
  const [routeCoords, setRouteCoords] = useState(null);
  const [alerts, setAlerts] = useState([]);
  const [mapRef, setMapRef] = useState(null);
  const [showHeatmap, setShowHeatmap] = useState(false);
  const overlayRef = useRef(null);

  // Dapatkan lokasi user saat pertama load
  useEffect(() => {
    navigator.geolocation?.getCurrentPosition(
      pos => {
        const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserLocation(loc);
        setOrigin({ ...loc, name: 'Lokasi Anda' });
        setMapCenter([loc.lat, loc.lng]);
        addAlert('Lokasi Anda ditemukan', 'success');
      },
      () => {
        const def = { lat: -2.9761, lng: 104.7754 };
        setUserLocation(def);
        setOrigin({ ...def, name: 'Palembang (Default)' });
      },
      { enableHighAccuracy: true, timeout: 8000 }
    );
  }, []);

  // Fetch cuaca & traffic
  useEffect(() => {
    const fetchData = async () => {
      try {
        const wRes = await weatherAPI.get(mapCenter[0], mapCenter[1]);
        if (wRes.data.success) setWeather(wRes.data.data);
      } catch { /* gunakan data simulasi */ }
    };
    fetchData();
    const interval = setInterval(fetchData, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  // Alert otomatis
  useEffect(() => {
    const alerts = [
      { msg: 'Kemacetan terdeteksi di Jl. Jend. Sudirman', type: 'warning', delay: 4000 },
      { msg: 'Peringatan: Hujan lebat pukul 17:00-19:00', type: 'warning', delay: 10000 },
      { msg: 'Area Ilir Barat I: permintaan driver tinggi!', type: 'success', delay: 18000 },
      { msg: 'Kecelakaan dilaporkan di Jl. MP Mangkunegara', type: 'danger', delay: 30000 },
    ];
    const timers = alerts.map(a => setTimeout(() => addAlert(a.msg, a.type), a.delay));
    return () => timers.forEach(clearTimeout);
  }, []);

  const addAlert = (msg, type = 'info') => {
    const id = Date.now();
    setAlerts(prev => [...prev.slice(-4), { id, msg, type }]);
    setTimeout(() => setAlerts(prev => prev.filter(a => a.id !== id)), 5000);
  };

  const handleDestinationSelect = useCallback(async (place) => {
  setDestination(place);
  setMapCenter([place.lat, place.lng]);
  setActivePanel(null);
  if (!origin) return;
  toast.loading('Menghitung rute...', { id: 'route' });
  try {
    const res = await routeAPI.calculate(origin, place, { vehicle: 'car', routeType: 'fastest' });
    const { routes, tripId } = res.data.data;
    if (routes && routes.length) {
      setActiveRoute(routes[0]);
      const coords = routes[0].geometry.coordinates.map(c => [c[1], c[0]]);
      setRouteCoords(coords);
      const eta = new Date(Date.now() + routes[0].duration * 1000);
      toast.success(`Rute: ${routes[0].distanceKm} km · ${routes[0].durationMin} mnt · ETA ${eta.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}`, { id: 'route', duration: 4000 });
      setActivePanel('route');
    } else throw new Error('Rute kosong');
  } catch (err) {
    toast.error('Gagal menghitung rute. Coba lagi.', { id: 'route' });
  }
}, [origin]);

  const handleClearRoute = () => {
    clearRoute();
    setRouteCoords(null);
    setActivePanel(null);
    toast('Rute dihapus', { icon: '🗑️' });
  };

  const handleLocateMe = () => {
    if (userLocation) {
      setMapCenter([userLocation.lat, userLocation.lng]);
      setMapZoom(15);
    } else {
      navigator.geolocation?.getCurrentPosition(pos => {
        const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserLocation(loc);
        setMapCenter([loc.lat, loc.lng]);
        setMapZoom(15);
      });
    }
  };

  const handleStartNav = () => {
  setActivePanel(null);           // tutup panel rute
  setIsNavigating(true);          // tampilkan panel navigasi
  setNavigationRoute(activeRoute); // simpan rute yang akan dinavigasi
  toast.success('Navigasi dimulai, ikuti petunjuk arah.');
};

  const handleStopNav = () => {
  setIsNavigating(false);
  setNavigationRoute(null);
  toast('Navigasi dihentikan.');
  // optional: clear route juga? terserah kebutuhan.
  // clearRoute();
};

  const panelProps = {
    onClose: () => setActivePanel(null),
    onDestinationSelect: handleDestinationSelect,
    onClearRoute: handleClearRoute,
    onStartNav: handleStartNav,
    onAlert: addAlert,
  };

  const panels = { search: SearchPanel, route: RoutePanel, ai: AIChatPanel, driver: DriverPanel, profile: ProfilePanel, weather: WeatherPanel, history: HistoryPanel, sos: SOSPanel, layers: LayersPanel };
  const ActivePanel = activePanel ? panels[activePanel] : null;

  return (
    <div className="screen" style={{ background: '#0D1117' }}>
      {/* MAP */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
        <MapContainer
          center={mapCenter} zoom={mapZoom}
          style={{ height: '100%', width: '100%' }}
          zoomControl={false} attributionControl={true}
          ref={setMapRef}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://openstreetmap.org">OpenStreetMap</a>'
            maxZoom={19}
          />
          <MapUpdater center={mapCenter} zoom={mapZoom} />

          {/* User location marker */}
          {userLocation && (
            <Marker position={[userLocation.lat, userLocation.lng]} icon={createIcon('#6B5CE7', 14)} />
          )}

          {/* Origin marker */}
          {origin && origin.lat !== userLocation?.lat && (
            <Marker position={[origin.lat, origin.lng]} icon={createPinIcon('#1FAD8E')} />
          )}

          {/* Destination marker */}
          {destination && (
            <Marker position={[destination.lat, destination.lng]} icon={createPinIcon('#D95050')} />
          )}

          {/* Route polyline */}
          {routeCoords && (
            <Polyline positions={routeCoords} color="#6B5CE7" weight={5} opacity={0.9} lineCap="round" lineJoin="round" />
          )}
        </MapContainer>
      </div>

      {/* TOP BAR */}
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, zIndex: 100, padding: '10px 12px' }}>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          {/* Search bar */}
          <div
            style={{ flex: 1, background: 'rgba(22,27,34,0.97)', border: '0.5px solid rgba(255,255,255,0.1)', borderRadius: 13, padding: '10px 13px', display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}
            onClick={() => { setActivePanel('search'); setActiveTab('search'); }}
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#8B949E" strokeWidth="2" strokeLinecap="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
            <span style={{ fontSize: 14, color: destination ? '#F0F6FC' : '#3D444D', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {destination?.name || 'Mau ke mana?'}
            </span>
            {destination && (
              <button onClick={e => { e.stopPropagation(); handleClearRoute(); }}
                style={{ background: 'none', border: 'none', color: '#8B949E', fontSize: 16, padding: 0 }}>×</button>
            )}
          </div>
          {/* Layers button */}
          <button
            style={{ width: 42, height: 42, background: 'rgba(22,27,34,0.97)', border: '0.5px solid rgba(255,255,255,0.1)', borderRadius: 11, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}
            onClick={() => setActivePanel('layers')}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#F0F6FC" strokeWidth="2" strokeLinecap="round"><polygon points="12 2 2 7 12 12 22 7 12 2"/><polyline points="2 17 12 22 22 17"/><polyline points="2 12 12 17 22 12"/></svg>
          </button>
        </div>
      </div>

      {/* WEATHER WIDGET */}
      <div
        style={{ position: 'absolute', top: 68, right: 12, zIndex: 100, background: 'rgba(22,27,34,0.97)', border: '0.5px solid rgba(255,255,255,0.1)', borderRadius: 11, padding: '8px 12px', cursor: 'pointer' }}
        onClick={() => setActivePanel('weather')}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 20, lineHeight: 1 }}>⛅</span>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700 }}>{weather?.temperature || 31}°C</div>
            <div style={{ fontSize: 10, color: '#8B949E' }}>{weather?.description || 'Berawan'}</div>
          </div>
        </div>
      </div>

      {/* ALERT OVERLAY */}
      <AlertOverlay alerts={alerts} />

      {/* MAP CONTROLS */}
      <MapControls onLocateMe={handleLocateMe} onSOS={() => setActivePanel('sos')} />

      {/* ROUTE INFO BAR */}
      {activeRoute && !activePanel && (
        <RouteBar
          route={activeRoute}
          destination={destination}
          onViewRoute={() => setActivePanel('route')}
          onCancel={handleClearRoute}
          onStart={handleStartNav}
        />
      )}

      {/* OVERLAY backdrop */}
      {activePanel && (
        <div
          style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.45)', zIndex: 140 }}
          onClick={() => setActivePanel(null)}
        />
      )}

      {/* ACTIVE PANEL */}
      {ActivePanel && (
        <ActivePanel
          {...panelProps}
          isOpen={true}
          route={activeRoute}
          origin={origin}
          destination={destination}
          weather={weather}
          userLocation={userLocation}
          showHeatmap={showHeatmap}
          onToggleHeatmap={() => setShowHeatmap(h => !h)}
        />
      )}
      {/* PANEL NAVIGASI AKTIF */}
        {isNavigating && navigationRoute && (
          <NavigationPanel
            isOpen={isNavigating}
            onClose={handleStopNav}
            route={navigationRoute}
            destination={destination}
            onStop={handleStopNav}
          />
        )}

      {/* BOTTOM NAV */}
      <NavBar
        active={activeTab}
        onTab={(tab) => {
          setActiveTab(tab);
          const panelMap = { home: null, search: 'search', driver: 'driver', ai: 'ai', profile: 'profile' };
          setActivePanel(panelMap[tab]);
        }}
      />
    </div>
  );
}
